+fn policy_surface_from_decision_context(decision_context: Option<&str>) -> String {
+    decision_context
+        .and_then(|raw| serde_json::from_str::<serde_json::Value>(raw).ok())
+        .and_then(|value| {
+            value
+                .get("surface")
+                .and_then(serde_json::Value::as_str)
+                .map(str::to_string)
+        })
+        .unwrap_or_else(|| "—".to_string())
+}
